using System.IO;
using System.Windows.Media;
using System.Windows.Media.Media3D;
using HelixToolkit.Wpf;

namespace TM12Viewer.Robot;

/// <summary>
/// URDF 기반 TM12 로봇 6축 관절 체인.
/// ModelVisual3D 중첩으로 kinematic chain 구성.
/// </summary>
public class RobotModel
{
    // 각 관절의 AxisAngleRotation3D (Angle 값만 변경하면 됨)
    private readonly AxisAngleRotation3D[] _jointRotations = new AxisAngleRotation3D[6];

    // 루트 ModelVisual3D (HelixViewport3D에 추가)
    public ModelVisual3D RootVisual { get; }

    // URDF 단위가 미터이므로 mm 변환 스케일
    private const double SCALE = 1000.0;

    public RobotModel()
    {
        // 관절 회전 초기화
        for (int i = 0; i < 6; i++)
            _jointRotations[i] = new AxisAngleRotation3D(new Vector3D(0, 0, 1), 0);

        RootVisual = BuildKinematicChain();
    }

    // TM Robot 보고 각도 → URDF 각도 오프셋 (J2: +90°)
    private static readonly double[] JointOffsets = [0, -90, 0, 0, 0, 0];

    /// <summary>
    /// 모든 관절 각도 설정 (도 단위, J1~J6)
    /// </summary>
    public void SetAllJointAngles(double[] angles)
    {
        for (int i = 0; i < Math.Min(angles.Length, 6); i++)
            _jointRotations[i].Angle = angles[i] + JointOffsets[i];
    }

    /// <summary>
    /// 개별 관절 각도 설정 (0-based index, 도 단위)
    /// </summary>
    public void SetJointAngle(int index, double angleDeg)
    {
        if (index >= 0 && index < 6)
            _jointRotations[index].Angle = angleDeg;
    }

    private ModelVisual3D BuildKinematicChain()
    {
        var material = CreateMaterial();
        var modelsDir = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "Models");

        // link_0 (base) - 고정
        var baseVisual = new ModelVisual3D();
        var baseMesh = LoadStl(Path.Combine(modelsDir, "tm12-base.stl"));
        if (baseMesh != null)
            baseVisual.Children.Add(CreateMeshVisual(baseMesh, material));

        // joint_1: origin=(0, 0, 0.1652) axis=Z
        var joint1Visual = CreateJointVisual(
            originXyz: new Vector3D(0, 0, 0.1652),
            originRpy: new Vector3D(0, 0, 0),
            jointIndex: 0);
        var link1Mesh = LoadStl(Path.Combine(modelsDir, "tmr_750w_01.stl"));
        if (link1Mesh != null)
            joint1Visual.Children.Add(CreateMeshVisual(link1Mesh, material));
        baseVisual.Children.Add(joint1Visual);

        // joint_2: origin=(0, 0, 0) rpy=(-90°, -90°, 0) axis=Z
        var joint2Visual = CreateJointVisual(
            originXyz: new Vector3D(0, 0, 0),
            originRpy: new Vector3D(-90, -90, 0),
            jointIndex: 1);
        var link2Mesh = LoadStl(Path.Combine(modelsDir, "tm12-arm1.stl"));
        if (link2Mesh != null)
            joint2Visual.Children.Add(CreateMeshVisual(link2Mesh, material));
        joint1Visual.Children.Add(joint2Visual);

        // joint_3: origin=(0.6361, 0, 0) axis=Z
        var joint3Visual = CreateJointVisual(
            originXyz: new Vector3D(0.6361, 0, 0),
            originRpy: new Vector3D(0, 0, 0),
            jointIndex: 2);
        var link3Mesh = LoadStl(Path.Combine(modelsDir, "tm12-arm2.stl"));
        if (link3Mesh != null)
            joint3Visual.Children.Add(CreateMeshVisual(link3Mesh, material));
        joint2Visual.Children.Add(joint3Visual);

        // joint_4: origin=(0.5579, 0, -0.1563) rpy=(0, 0, 90°) axis=Z
        var joint4Visual = CreateJointVisual(
            originXyz: new Vector3D(0.5579, 0, -0.1563),
            originRpy: new Vector3D(0, 0, 90),
            jointIndex: 3);
        var link4Mesh = LoadStl(Path.Combine(modelsDir, "tmr_100w_01.stl"));
        if (link4Mesh != null)
            joint4Visual.Children.Add(CreateMeshVisual(link4Mesh, material));
        joint3Visual.Children.Add(joint4Visual);

        // joint_5: origin=(0, -0.106, 0) rpy=(90°, 0, 0) axis=Z
        var joint5Visual = CreateJointVisual(
            originXyz: new Vector3D(0, -0.106, 0),
            originRpy: new Vector3D(90, 0, 0),
            jointIndex: 4);
        var link5Mesh = LoadStl(Path.Combine(modelsDir, "tmr_100w_02.stl"));
        if (link5Mesh != null)
            joint5Visual.Children.Add(CreateMeshVisual(link5Mesh, material));
        joint4Visual.Children.Add(joint5Visual);

        // joint_6: origin=(0, -0.11315, 0) rpy=(90°, 0, 0) axis=Z
        var joint6Visual = CreateJointVisual(
            originXyz: new Vector3D(0, -0.11315, 0),
            originRpy: new Vector3D(90, 0, 0),
            jointIndex: 5);
        var link6Mesh = LoadStl(Path.Combine(modelsDir, "tmr_ee.stl"));
        if (link6Mesh != null)
            joint6Visual.Children.Add(CreateMeshVisual(link6Mesh, material));

        // OnRobot 툴 (mm 단위, 로봇 본체와 동일 재질)
        // Angle Bracket 90° (플랜지에 직접 장착)
        var abMesh = LoadStlMm(Path.Combine(modelsDir, "angle_bracket.stl"));
        if (abMesh != null)
        {
            var abVisual = CreateMeshVisual(abMesh, material);
            var abTransform = new Transform3DGroup();
            abTransform.Children.Add(new RotateTransform3D(
                new AxisAngleRotation3D(new Vector3D(1, 0, 0), -270)));
            abTransform.Children.Add(new ScaleTransform3D(-1, 1, 1));
            abVisual.Transform = abTransform;
            joint6Visual.Children.Add(abVisual);
        }

        // Quick Changer (브라켓 볼트홀 면에 연결)
        var qcMesh = LoadStlMm(Path.Combine(modelsDir, "quick_changer_robot.stl"));
        if (qcMesh != null)
        {
            var qcVisual = CreateMeshVisual(qcMesh, material);
            var qcTransform = new Transform3DGroup();
            // QC +Y면 → +X 방향 (브라켓 볼트홀과 맞닿음)
            qcTransform.Children.Add(new RotateTransform3D(
                new AxisAngleRotation3D(new Vector3D(0, 0, 1), -90)));
            qcTransform.Children.Add(new TranslateTransform3D(-42, 0, 66));
            qcVisual.Transform = qcTransform;
            joint6Visual.Children.Add(qcVisual);
        }

        // Screwdriver (QC tool side에 연결)
        var sdMesh = LoadStlMm(Path.Combine(modelsDir, "screwdriver.stl"));
        if (sdMesh != null)
        {
            var sdVisual = CreateMeshVisual(sdMesh, material);
            var sdTransform = new Transform3DGroup();
            // 회전 없이 원본
            sdTransform.Children.Add(new TranslateTransform3D(-42, 54, 231));
            sdVisual.Transform = sdTransform;
            joint6Visual.Children.Add(sdVisual);
        }

        joint5Visual.Children.Add(joint6Visual);

        return baseVisual;
    }

    /// <summary>
    /// 관절 Visual 생성: URDF origin(xyz+rpy) 고정 변환 + 관절 회전
    /// WPF Transform3DGroup 적용 순서: 이동 → RPY 회전 → 관절 회전
    /// </summary>
    private ModelVisual3D CreateJointVisual(Vector3D originXyz, Vector3D originRpy, int jointIndex)
    {
        var visual = new ModelVisual3D();
        var transformGroup = new Transform3DGroup();

        // 1) 관절 회전 (Z축 기준, 실시간 변경) — 가장 안쪽(로컬)
        transformGroup.Children.Add(new RotateTransform3D(_jointRotations[jointIndex]));

        // 2) URDF origin rpy 고정 회전 (Z→Y→X 역순 적용)
        if (originRpy.X != 0 || originRpy.Y != 0 || originRpy.Z != 0)
        {
            if (originRpy.Z != 0)
                transformGroup.Children.Add(new RotateTransform3D(
                    new AxisAngleRotation3D(new Vector3D(0, 0, 1), originRpy.Z)));
            if (originRpy.Y != 0)
                transformGroup.Children.Add(new RotateTransform3D(
                    new AxisAngleRotation3D(new Vector3D(0, 1, 0), originRpy.Y)));
            if (originRpy.X != 0)
                transformGroup.Children.Add(new RotateTransform3D(
                    new AxisAngleRotation3D(new Vector3D(1, 0, 0), originRpy.X)));
        }

        // 3) URDF origin xyz 이동 (미터 → mm 스케일 적용) — 가장 바깥쪽(부모 좌표)
        transformGroup.Children.Add(new TranslateTransform3D(
            originXyz.X * SCALE, originXyz.Y * SCALE, originXyz.Z * SCALE));

        visual.Transform = transformGroup;
        return visual;
    }

    /// <summary>
    /// STL 파일 로딩 — mm 단위 (스케일 변환 없음)
    /// </summary>
    private static Model3DGroup? LoadStlMm(string filePath)
    {
        if (!File.Exists(filePath))
        {
            System.Diagnostics.Debug.WriteLine($"[RobotModel] STL 파일 없음: {filePath}");
            return null;
        }
        try
        {
            var reader = new StLReader();
            return reader.Read(filePath);
        }
        catch (Exception ex)
        {
            System.Diagnostics.Debug.WriteLine($"[RobotModel] STL 로드 예외: {filePath} - {ex.Message}");
            return null;
        }
    }

    /// <summary>
    /// STL 파일 로딩 (HelixToolkit StLReader 사용)
    /// 실패 시 Debug 출력 + Trace 로그
    /// </summary>
    private static Model3DGroup? LoadStl(string filePath)
    {
        if (!File.Exists(filePath))
        {
            var msg = $"[RobotModel] STL 파일 없음: {filePath}";
            System.Diagnostics.Debug.WriteLine(msg);
            System.Diagnostics.Trace.TraceWarning(msg);
            return null;
        }

        try
        {
            var reader = new StLReader();
            var model = reader.Read(filePath);
            if (model == null)
            {
                var msg = $"[RobotModel] STL 로드 실패 (null 반환): {filePath}";
                System.Diagnostics.Debug.WriteLine(msg);
                System.Diagnostics.Trace.TraceWarning(msg);
                return null;
            }
            // URDF STL은 미터 단위 → mm 변환
            model.Transform = new ScaleTransform3D(SCALE, SCALE, SCALE);
            return model;
        }
        catch (Exception ex)
        {
            var msg = $"[RobotModel] STL 로드 예외: {filePath} - {ex.Message}";
            System.Diagnostics.Debug.WriteLine(msg);
            System.Diagnostics.Trace.TraceError(msg);
            return null;
        }
    }

    /// <summary>
    /// 메시 Visual 생성
    /// </summary>
    private static ModelVisual3D CreateMeshVisual(Model3DGroup meshGroup, Material material)
    {
        // 모든 GeometryModel3D에 material 적용
        foreach (var model in meshGroup.Children)
        {
            if (model is GeometryModel3D geoModel)
            {
                geoModel.Material = material;
                geoModel.BackMaterial = material;
            }
        }

        return new ModelVisual3D { Content = meshGroup };
    }

    /// <summary>
    /// OnRobot Screwdriver 임시 형상 생성 (308 x 86 x 114mm)
    /// 플랜지 기준 Z축 방향으로 본체 + 비트
    /// </summary>
    private static ModelVisual3D CreateScrewdriverVisual()
    {
        var screwdriver = new ModelVisual3D();

        // 스크류드라이버 재질 (진한 파란색)
        var bodyMat = new MaterialGroup();
        bodyMat.Children.Add(new DiffuseMaterial(new SolidColorBrush(Color.FromRgb(40, 60, 120))));
        bodyMat.Children.Add(new SpecularMaterial(new SolidColorBrush(Color.FromRgb(80, 80, 80)), 40));

        // 비트 재질 (은색)
        var bitMat = new MaterialGroup();
        bitMat.Children.Add(new DiffuseMaterial(new SolidColorBrush(Color.FromRgb(180, 180, 190))));
        bitMat.Children.Add(new SpecularMaterial(new SolidColorBrush(Color.FromRgb(120, 120, 120)), 60));

        // 본체: 플랜지 어댑터 (직경 86mm, 높이 30mm)
        screwdriver.Children.Add(new ModelVisual3D
        {
            Content = new GeometryModel3D(BuildCylinder(43, 0, 30, 24), bodyMat) { BackMaterial = bodyMat }
        });
        // 본체: 메인 바디 (직경 80mm, 높이 200mm)
        screwdriver.Children.Add(new ModelVisual3D
        {
            Content = new GeometryModel3D(BuildCylinder(40, 30, 230, 24), bodyMat) { BackMaterial = bodyMat }
        });
        // 본체: 선단부 테이퍼 (직경 50mm, 높이 40mm)
        screwdriver.Children.Add(new ModelVisual3D
        {
            Content = new GeometryModel3D(BuildCylinder(25, 230, 270, 24), bodyMat) { BackMaterial = bodyMat }
        });
        // 비트: 가는 원통 (직경 8mm, 길이 38mm)
        screwdriver.Children.Add(new ModelVisual3D
        {
            Content = new GeometryModel3D(BuildCylinder(4, 270, 308, 12), bitMat) { BackMaterial = bitMat }
        });

        return screwdriver;
    }

    /// <summary>
    /// Z축 방향 원통 메시 생성 (중심 0,0, 반지름 r, z0~z1)
    /// </summary>
    private static MeshGeometry3D BuildCylinder(double radius, double z0, double z1, int segments)
    {
        var mesh = new MeshGeometry3D();
        var positions = mesh.Positions;
        var indices = mesh.TriangleIndices;

        // 상단/하단 원 정점 생성
        for (int i = 0; i < segments; i++)
        {
            double angle = 2 * Math.PI * i / segments;
            double x = radius * Math.Cos(angle);
            double y = radius * Math.Sin(angle);
            positions.Add(new Point3D(x, y, z0)); // 하단
            positions.Add(new Point3D(x, y, z1)); // 상단
        }

        // 측면 삼각형
        for (int i = 0; i < segments; i++)
        {
            int next = (i + 1) % segments;
            int b0 = i * 2, t0 = i * 2 + 1;
            int b1 = next * 2, t1 = next * 2 + 1;
            indices.Add(b0); indices.Add(b1); indices.Add(t1);
            indices.Add(b0); indices.Add(t1); indices.Add(t0);
        }

        // 상단/하단 캡 중심점
        int centerBottom = positions.Count;
        positions.Add(new Point3D(0, 0, z0));
        int centerTop = positions.Count;
        positions.Add(new Point3D(0, 0, z1));

        for (int i = 0; i < segments; i++)
        {
            int next = (i + 1) % segments;
            // 하단 캡
            indices.Add(centerBottom); indices.Add(next * 2); indices.Add(i * 2);
            // 상단 캡
            indices.Add(centerTop); indices.Add(i * 2 + 1); indices.Add(next * 2 + 1);
        }

        return mesh;
    }

    /// <summary>
    /// 로봇 재질 생성 (밝은 회색 + 반사)
    /// </summary>
    private static MaterialGroup CreateMaterial()
    {
        var materialGroup = new MaterialGroup();
        materialGroup.Children.Add(new DiffuseMaterial(new SolidColorBrush(Color.FromRgb(200, 200, 210))));
        materialGroup.Children.Add(new SpecularMaterial(new SolidColorBrush(Color.FromRgb(100, 100, 100)), 50));
        return materialGroup;
    }
}
